  it("formats 0.999 as 99.9%", () => expect(formatProbability(0.999)).toBe("99.9%"));
});

describe("formatCurrency", () => {
  it("formats large numbers with K suffix", () => expect(formatCurrency(45000)).toBe("45.0K"));
